// // This is a 32-to-5 decoder that takes a 32-bit binary input and activates one of the 5 outputs based on the binary value of the input.
module decoder_5_to_32(  
    input [4:0] A,  
    output reg [31:0] Y  
);  
    always @(*) begin  
        Y = 32'b0;  
        Y[A] = 1'b1;  
    end  
endmodule
